import { CommonModule } from '@angular/common';
import { Component, OnInit } from '@angular/core';
import { RouterLink, RouterOutlet } from '@angular/router';
import { AuthUser } from './models';
import { AuthService } from './services/auth.service';
import { CartService } from './services/cart.service';

@Component({
  selector: 'app-root',
  standalone: true,
  imports: [CommonModule, RouterLink, RouterOutlet],
  template: `
    <div class="shell">
      <header class="topbar">
        <div class="topbar__brand">Tienda de Productos</div>
        <nav class="topbar__nav">
          <a routerLink="/">Catálogo</a>
          <a routerLink="/carrito">Carrito</a>
          <a routerLink="/auth" *ngIf="!user">Ingresar</a>
          <a href="#" *ngIf="user" (click)="logout($event)">Salir</a>
          <a href="/" *ngIf="user?.rol === 'administrativo'">Panel admin</a>
        </nav>
      </header>

      <section class="container" *ngIf="user" style="padding-top: 1rem;">
        <div class="card">
          Sesión: <strong>{{ user.nombre }}</strong> · {{ user.rol }}
        </div>
      </section>

      <main class="container">
        <router-outlet />
      </main>
    </div>
  `,
})
export class AppComponent implements OnInit {
  user: AuthUser | null = null;

  constructor(
    private readonly auth: AuthService,
    private readonly cart: CartService,
  ) {}

  ngOnInit(): void {
    this.auth.loadSession();
    this.user = this.auth.snapshot;
    this.auth.user$.subscribe((user) => {
      this.user = user;
    });
    this.cart.loadCart();
  }

  logout(event: Event): void {
    event.preventDefault();
    this.auth.logout().subscribe({
      next: () => {
        this.auth.setUser(null);
        this.cart.loadCart();
      },
    });
  }
}
